mapper.select:
SELECT wo.id, wo.order_no, wo.order_type, CASE wo.order_type WHEN 1 THEN '报修' WHEN 2 THEN '保养' WHEN 3 THEN '安装调试' WHEN 4 THEN '巡检' ELSE '其他' END AS order_type_name, wo.order_status, CASE wo.order_status WHEN 0 THEN '待派单' WHEN 1 THEN '待接单' WHEN 2 THEN '处理中' WHEN 3 THEN '待验收' WHEN 4 THEN '已完成' WHEN 5 THEN '已关闭' WHEN 6 THEN '已取消' ELSE '未知' END AS order_status_name, eq.equipment_code, eq.equipment_name, cus.customer_name, wo.reporter_name, wo.reporter_phone, wo.fault_description, wo.fault_level, CASE wo.fault_level WHEN 1 THEN '紧急' WHEN 2 THEN '高' WHEN 3 THEN '中' WHEN 4 THEN '低' ELSE '未知' END AS fault_level_name, us.real_name AS assignee_name, wo.assign_time, wo.accept_time, wo.arrive_time, wo.finish_time, wo.handling_detail, wo.rating, wo.create_time FROM tbl_work_order wo LEFT JOIN tbl_equipment eq ON wo.equipment_id = eq.id AND eq.deleted = 0 LEFT JOIN tbl_customer cus ON wo.customer_id = cus.id AND cus.deleted = 0 LEFT JOIN tbl_sys_user us ON wo.assignee_id = us.id AND us.deleted = 0
wo.deleted = 0
AND wo.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND eq.equipment_code LIKE CONCAT('%', #{equipmentCode}, '%')
AND wo.order_status = #{orderStatus}
AND wo.customer_id = #{customerId}
AND wo.assignee_id = #{assigneeId}
AND wo.order_type = #{orderType}
AND wo.create_time >= #{startTime}
AND wo.create_time <= #{endTime}
ORDER BY wo.create_time DESC

SELECT COUNT(1) FROM tbl_work_order wo
LEFT JOIN tbl_equipment eq ON wo.equipment_id = eq.id AND eq.deleted = 0

    wo.deleted = 0

        AND wo.order_no LIKE CONCAT('%', #{orderNo}, '%')


        AND eq.equipment_code LIKE CONCAT('%', #{equipmentCode}, '%')


        AND wo.order_status = #{orderStatus}


        AND wo.customer_id = #{customerId}


        AND wo.assignee_id = #{assigneeId}


        AND wo.order_type = #{orderType}


        AND wo.create_time >= #{startTime}


        AND wo.create_time <= #{endTime}
